class Solution:
    def rearrangeCharacters(self, s: str, target: str) -> int:
        s_count = {}
        target_count = {}
        for char in s:
            if char not in s_count:
                s_count[char] = 0
            s_count[char] += 1
        for char in target:
            if char not in target_count:
                target_count[char] = 0
            target_count[char] += 1
        res = float('inf')
        for char in target_count:
            if char not in s_count:
                return 0
            res = min(res, s_count[char] // target_count[char])
        return res
